snippets.example:
.btn-primary {
  background: #FF5000;
  color: #FFFFFF;
  border-radius: 6px;
  height: 28px;
  padding: 0 12px;
  font-weight: 600;
  font-size: 14px;
  transition: background 200ms ease-out, box-shadow 200ms ease-out;
}
.btn-primary:hover {
  background: #E04800;
  box-shadow: 0 2px 8px rgba(255, 80, 0, 0.3);
}
.btn-primary:focus-visible {
  outline: 2px solid #FF5000;
  outline-offset: 2px;
}

.card {
  background: #EBEBEB;
  border-radius: 8px;
  padding: 16px;
  box-shadow: 0px 4px 24px rgba(10,10,51,0.12), 0px 0px 8px rgba(0,0,0,0.04);
  transition: transform 200ms ease-out, box-shadow 200ms ease-out;
}
.card:hover {
  transform: translateY(-2px);
  box-shadow: 0px 8px 32px rgba(10,10,51,0.15), 0px 0px 12px rgba(0,0,0,0.06);
}

.input {
  background: #FFFFFF;
  color: #1F1F1F;
  border: 1px solid #EBEBEB;
  border-radius: 4px;
  height: 36px;
  padding: 0 12px;
  font-size: 14px;
  transition: border-color 200ms ease-out;
}
.input:hover {
  border-color: #7A7A7A;
}
.input:focus {
  outline: 2px solid #FF5000;
  outline-offset: 2px;
  border-color: #FF5000;
}

body {
  background: #FFFFFF;
  margin: 0;
}
.container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px; /* 使用 space-lg 作为边距 */
}
.grid {
  display: grid;
  grid-template-columns: repeat(12, 1fr);
  gap: 24px; /* 使用 space-lg 作为网格间距 */
}
